'use client';

import { useState, useEffect, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import styles from './account.module.css';
import AuthModal from '@/components/AuthModal/AuthModal';
import BottomNav from '@/components/BottomNav/BottomNav';
import DesktopNav from '@/components/DesktopNav/DesktopNav';
import UserAvatar from '@/components/UserAvatar/UserAvatar';
import { supabase } from '@/lib/supabase';
import type { Profile, Post } from '@/lib/types';
import { getRelativeTime } from '@/lib/geo';

interface UserStats {
  postsCount: number;
  stallsCount: number;
  reviewsCount: number;
}

interface Review {
  id: string;
  rating: number;
  note: string | null;
  created_at: string;
  stall_id: string;
  stalls: { name: string; category: string };
}



// Star rating
function Stars({ rating }: { rating: number }) {
  return (
    <div className={styles.reviewStars}>
      {[1, 2, 3, 4, 5].map((i) => (
        <svg
          key={i}
          viewBox="0 0 24 24"
          fill={i <= rating ? 'var(--rating-gold)' : 'none'}
          stroke={i <= rating ? 'var(--rating-gold)' : 'var(--gray-600)'}
          strokeWidth="1.5"
          width="13"
          height="13"
        >
          <polygon points="12,2 15.09,8.26 22,9.27 17,14.14 18.18,21.02 12,17.77 5.82,21.02 7,14.14 2,9.27 8.91,8.26" />
        </svg>
      ))}
    </div>
  );
}

export default function AccountPage() {
  const router = useRouter();
  const [userId, setUserId] = useState<string | null>(null);
  const [profile, setProfile] = useState<Profile | null>(null);
  const [stats, setStats] = useState<UserStats>({ postsCount: 0, stallsCount: 0, reviewsCount: 0 });
  const [posts, setPosts] = useState<Post[]>([]);
  const [reviews, setReviews] = useState<Review[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAuth, setShowAuth] = useState(false);
  const [selectedPost, setSelectedPost] = useState<Post | null>(null);
  const [activeSection, setActiveSection] = useState<'posts' | 'reviews'>('posts');

  const loadProfile = useCallback(async (uid: string) => {
    setLoading(true);
    try {
      // Profile
      const { data: profileData } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', uid)
        .single();
      setProfile(profileData ?? null);

      // Stats + content in parallel
      const [postsRes, stallsRes, reviewsRes, postsData, userReviews] = await Promise.all([
        supabase.from('posts').select('id', { count: 'exact', head: true }).eq('user_id', uid),
        supabase.from('stalls').select('id', { count: 'exact', head: true }).eq('created_by', uid),
        supabase.from('ratings').select('id', { count: 'exact', head: true }).eq('user_id', uid),
        supabase
          .from('posts')
          .select('*, stalls(name, category, avg_rating)')
          .eq('user_id', uid)
          .not('photo_url', 'is', null)
          .order('created_at', { ascending: false })
          .limit(30),
        supabase
          .from('ratings')
          .select('id, rating, note, created_at, stall_id, stalls(name, category)')
          .eq('user_id', uid)
          .order('created_at', { ascending: false })
          .limit(20),
      ]);

      setStats({
        postsCount: postsRes.count ?? 0,
        stallsCount: stallsRes.count ?? 0,
        reviewsCount: reviewsRes.count ?? 0,
      });
      setPosts((postsData.data as Post[]) ?? []);
      setReviews((userReviews.data as unknown as Review[]) ?? []);
    } catch (err) {
      console.error('Failed to load profile:', err);
    }
    setLoading(false);
  }, []);

  // Auth
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      const uid = session?.user?.id ?? null;
      setUserId(uid);
      if (uid) loadProfile(uid);
      else setLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_, session) => {
      const uid = session?.user?.id ?? null;
      setUserId(uid);
      if (uid) loadProfile(uid);
      else { setProfile(null); setPosts([]); setReviews([]); setLoading(false); }
    });

    return () => subscription.unsubscribe();
  }, []); // eslint-disable-line react-hooks/exhaustive-deps


  const handleSignOut = async () => {
    await supabase.auth.signOut();
    router.push('/');
  };

  // ── Not logged in ──
  if (!loading && !userId) {
    return (
      <div className={styles.page}>
        <header className={styles.header}>
          <button className={styles.backBtn} onClick={() => router.push('/')} aria-label="Go back">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
              <polyline points="15 18 9 12 15 6" />
            </svg>
          </button>
          <span className={styles.headerTitle}>Account</span>
          <div className={styles.headerRight}>
            <DesktopNav
              activeTab="account"
              userId={null}
              onAddClick={() => setShowAuth(true)}
              onSignInRequired={() => setShowAuth(true)}
            />
          </div>
          <div className={styles.headerSpacer} />
        </header>

        <div className={styles.signInPrompt}>
          <div className={styles.signInIconWrap}>
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.2" className={styles.signInSvg}>
              <path strokeLinecap="round" d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" />
              <circle cx="12" cy="7" r="4" />
            </svg>
          </div>
          <h1 className={styles.signInTitle}>Sign in to your profile</h1>
          <p className={styles.signInHint}>Share street food discoveries, rate stalls, and build your foodie identity.</p>
          <button
            id="account-signin-btn"
            className={`btn btn-primary ${styles.signInBtn}`}
            onClick={() => setShowAuth(true)}
          >
            Sign In
          </button>
        </div>

        {showAuth && <AuthModal onClose={() => setShowAuth(false)} />}

        <BottomNav
          activeTab="account"
          userId={null}
          onAddClick={() => setShowAuth(true)}
          onSignInRequired={() => setShowAuth(true)}
        />
      </div>
    );
  }

  const displayName = profile?.username || 'Foodie';

  return (
    <div className={styles.page}>
      {/* ── Header ── */}
      <header className={styles.header}>
        <button className={styles.backBtn} onClick={() => router.push('/')} aria-label="Go back">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
            <polyline points="15 18 9 12 15 6" />
          </svg>
        </button>
        <span className={styles.headerTitle}>{displayName}</span>
        <div className={styles.headerRight}>
          <DesktopNav
            activeTab="account"
            userId={userId}
            onAddClick={() => router.push('/?add=true')}
            onSignInRequired={() => setShowAuth(true)}
          />
          <button id="signout-btn" className={styles.signOutBtn} onClick={handleSignOut} aria-label="Sign out">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" width="18" height="18">
              <path strokeLinecap="round" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
            </svg>
          </button>
        </div>
      </header>

      <div className={styles.scroll}>
        {/* ── Profile Hero ── */}
        <section className={styles.profileSection}>
          {/* Avatar */}
          <div className={styles.avatarWrapper}>
            <UserAvatar 
              name={displayName} 
              src={profile?.avatar_url} 
              size={88} 
            />
          </div>

          {/* Name */}
          <div className={styles.profileInfo}>
            <h1 className={styles.displayName}>{displayName}</h1>
            {Boolean((profile as Record<string, unknown>)?.bio) && <p className={styles.bio}>{String((profile as Record<string, unknown>).bio)}</p>}
          </div>

          {/* Stats row */}
          <div className={styles.statsRow}>
            <div className={styles.stat}>
              <span className={styles.statNumber}>{stats.postsCount}</span>
              <span className={styles.statLabel}>Posts</span>
            </div>
            <div className={styles.statDivider} />
            <div className={styles.stat}>
              <span className={styles.statNumber}>{stats.stallsCount}</span>
              <span className={styles.statLabel}>Stalls</span>
            </div>
            <div className={styles.statDivider} />
            <div className={styles.stat}>
              <span className={styles.statNumber}>{stats.reviewsCount}</span>
              <span className={styles.statLabel}>Reviews</span>
            </div>
          </div>
        </section>

        {/* ── Section Toggle ── */}
        <div className={styles.sectionToggle}>
          <button
            className={`${styles.toggleBtn} ${activeSection === 'posts' ? styles.toggleBtnActive : ''}`}
            onClick={() => setActiveSection('posts')}
            aria-label="Show posts"
          >
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" width="20" height="20">
              <rect x="3" y="3" width="7" height="7" rx="1" />
              <rect x="14" y="3" width="7" height="7" rx="1" />
              <rect x="14" y="14" width="7" height="7" rx="1" />
              <rect x="3" y="14" width="7" height="7" rx="1" />
            </svg>
          </button>
          <button
            className={`${styles.toggleBtn} ${activeSection === 'reviews' ? styles.toggleBtnActive : ''}`}
            onClick={() => setActiveSection('reviews')}
            aria-label="Show reviews"
          >
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" width="20" height="20">
              <polygon points="12,2 15.09,8.26 22,9.27 17,14.14 18.18,21.02 12,17.77 5.82,21.02 7,14.14 2,9.27 8.91,8.26" />
            </svg>
          </button>
        </div>

        {/* ── Posts Grid ── */}
        {activeSection === 'posts' && (
          <>
            {loading ? (
              <div className={styles.postsGrid}>
                {[...Array(9)].map((_, i) => (
                  <div key={i} className={`${styles.gridItemSkeleton} skeleton`} />
                ))}
              </div>
            ) : posts.length > 0 ? (
              <div className={styles.postsGrid}>
                {posts.map((post) => (
                  <button
                    key={post.id}
                    id={`post-grid-${post.id}`}
                    className={styles.gridItem}
                    onClick={() => setSelectedPost(post)}
                    aria-label={post.caption || 'View post'}
                  >
                    <img
                      src={post.photo_url!}
                      alt={post.caption || 'Post photo'}
                      className={styles.gridImg}
                      loading="lazy"
                    />
                    {post.rating && (
                      <div className={styles.gridRating}>
                        <svg viewBox="0 0 24 24" fill="var(--rating-gold)" width="10" height="10">
                          <polygon points="12,2 15.09,8.26 22,9.27 17,14.14 18.18,21.02 12,17.77 5.82,21.02 7,14.14 2,9.27 8.91,8.26" />
                        </svg>
                        {post.rating}
                      </div>
                    )}
                  </button>
                ))}
              </div>
            ) : (
              <div className={styles.noContent}>
                <span className={styles.noContentIcon}>📸</span>
                <p className={styles.noContentText}>No posts yet</p>
                <p className={styles.noContentHint}>Share your first street food discovery!</p>
              </div>
            )}
          </>
        )}

        {/* ── Reviews List ── */}
        {activeSection === 'reviews' && (
          <>
            {loading ? (
              <div className={styles.reviewsList}>
                {[...Array(4)].map((_, i) => (
                  <div key={i} className={`${styles.reviewSkeleton} skeleton`} />
                ))}
              </div>
            ) : reviews.length > 0 ? (
              <div className={styles.reviewsList}>
                {reviews.map((review) => (
                  <div key={review.id} className={styles.reviewCard}>
                    <div className={styles.reviewTop}>
                      <div className={styles.reviewLeft}>
                        <span className={styles.reviewStallName}>{review.stalls?.name ?? 'Unknown Stall'}</span>
                        <span className={styles.reviewCategory}>{review.stalls?.category}</span>
                      </div>
                      <div className={styles.reviewRight}>
                        <Stars rating={review.rating} />
                        <span className={styles.reviewTime}>{getRelativeTime(review.created_at)}</span>
                      </div>
                    </div>
                    {review.comment && (
                      <p className={styles.reviewComment}>{review.comment}</p>
                    )}
                  </div>
                ))}
              </div>
            ) : (
              <div className={styles.noContent}>
                <span className={styles.noContentIcon}>⭐</span>
                <p className={styles.noContentText}>No reviews yet</p>
                <p className={styles.noContentHint}>Rate stalls you&apos;ve visited on the map!</p>
              </div>
            )}
          </>
        )}

        <div className={styles.bottomSpacer} />
      </div>

      {/* Post detail overlay */}
      {selectedPost && (
        <div className={styles.postOverlay} onClick={() => setSelectedPost(null)}>
          <div className={styles.postDetail} onClick={(e) => e.stopPropagation()}>
            <button className={styles.postDetailClose} onClick={() => setSelectedPost(null)} aria-label="Close">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" width="20" height="20">
                <line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" />
              </svg>
            </button>
            {selectedPost.photo_url && (
              <img src={selectedPost.photo_url} alt="Post" className={styles.postDetailImg} />
            )}
            {selectedPost.caption && <p className={styles.postDetailCaption}>{selectedPost.caption}</p>}
            {selectedPost.rating && (
              <div className={styles.postDetailRating}>
                <Stars rating={selectedPost.rating} />
              </div>
            )}
          </div>
        </div>
      )}

      <BottomNav
        activeTab="account"
        userId={userId}
        onAddClick={() => router.push('/')}
        onSignInRequired={() => setShowAuth(true)}
      />

      {showAuth && <AuthModal onClose={() => setShowAuth(false)} />}
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import styles from './saved.module.css';
import { supabase } from '@/lib/supabase';
import { useSavedStalls } from '@/lib/useSavedStalls';
import type { Stall } from '@/lib/types';
import BottomNav from '@/components/BottomNav/BottomNav';
import DesktopNav from '@/components/DesktopNav/DesktopNav';
import AuthModal from '@/components/AuthModal/AuthModal';

export default function SavedPage() {
  const router = useRouter();
  const { savedStallIds, toggleSave, isHydrated } = useSavedStalls();
  const [stalls, setStalls] = useState<Stall[]>([]);
  const [loading, setLoading] = useState(true);
  const [userId, setUserId] = useState<string | null>(null);
  const [showAuth, setShowAuth] = useState(false);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUserId(session?.user?.id ?? null);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_, session) => {
      setUserId(session?.user?.id ?? null);
    });
    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    async function loadSavedStalls() {
      if (savedStallIds.length === 0) {
        setStalls([]);
        setLoading(false);
        return;
      }
      setLoading(true);
      try {
        const { data, error } = await supabase
          .from('stalls')
          .select('*')
          .in('id', savedStallIds);

        if (data && !error) {
          // Sort matched stalls based on recently saved order (end of array = newest)
          const sorted = data.sort((a, b) => {
            return savedStallIds.indexOf(b.id) - savedStallIds.indexOf(a.id);
          });
          setStalls(sorted as Stall[]);
        }
      } catch (err) {
        console.error('Error fetching saved stalls:', err);
      }
      setLoading(false);
    }
    if (isHydrated) {
      loadSavedStalls();
    }
  }, [savedStallIds, isHydrated]);

  const handleCardClick = (stallId: string) => {
    router.push(`/map?stall=${stallId}`);
  };

  const handleRemove = (e: React.MouseEvent, stallId: string) => {
    e.stopPropagation();
    toggleSave(stallId);
  };

  return (
    <div className={styles.page}>
      <header className={styles.header}>
        <div className={styles.title}>Saved</div>
        <div className={styles.headerRight}>
          <DesktopNav
            activeTab="saved"
            userId={userId}
            onAddClick={() => {
               if (!userId) setShowAuth(true);
               else router.push('/?add=true');
            }}
            onSignInRequired={() => setShowAuth(true)}
          />
        </div>
      </header>

      <main className={styles.main}>
        {!isHydrated || loading ? (
          <div className={styles.loader}>
            <div className={styles.spinner} style={{ width: 24, height: 24, border: '2px solid var(--text-tertiary)', borderTopColor: 'var(--text-primary)', borderRadius: '50%', animation: 'spin 0.7s linear infinite' }} />
          </div>
        ) : stalls.length > 0 ? (
          <div className={styles.grid}>
            {stalls.map((stall) => (
              <div key={stall.id} className={styles.card} onClick={() => handleCardClick(stall.id)}>
                <div className={styles.imageWrapper}>
                  {stall.photo_url ? (
                    <img src={stall.photo_url} alt={stall.name} className={styles.image} />
                  ) : (
                    <div className={styles.placeholder}>
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                        <rect x="3" y="3" width="18" height="18" rx="2" />
                        <circle cx="8.5" cy="8.5" r="1.5" />
                        <polyline points="21 15 16 10 5 21" />
                      </svg>
                    </div>
                  )}
                </div>

                <div className={styles.content}>
                  <div className={styles.infoTop}>
                    <div className={styles.name}>{stall.name}</div>
                    <div className={styles.category}>{stall.category}</div>
                  </div>
                  <div className={styles.infoBottom}>
                    <div className={styles.rating}>★ {Number(stall.avg_rating || 0).toFixed(1)}</div>
                    <button className={styles.removeBtn} onClick={(e) => handleRemove(e, stall.id)} aria-label="Remove from saved">
                      <svg viewBox="0 0 24 24" fill="currentColor" stroke="currentColor" strokeWidth="2">
                        <path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z" />
                      </svg>
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className={styles.empty}>
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z" />
            </svg>
            <div className={styles.emptyText}>No saved stalls yet.</div>
          </div>
        )}
        <div className={styles.bottomSpacer} />
      </main>

      {showAuth && <AuthModal onClose={() => setShowAuth(false)} />}

      <BottomNav
        activeTab="saved"
        userId={userId}
        onAddClick={() => {
          if (!userId) setShowAuth(true);
          // Assuming AddModal would be implemented globally or triggered via context in real app
          else router.push('/?add=true'); // Fallback
        }}
        onSignInRequired={() => setShowAuth(true)}
      />
    </div>
  );
}

'use client';

import { useState, useRef, useCallback, useEffect } from 'react';
import Image from 'next/image';
import styles from './AddModal.module.css';
import RatingStars from '@/components/RatingStars/RatingStars';
import { CATEGORIES, type Category } from '@/lib/types';
import { DEFAULT_LOCATION, getCurrentPosition, type Coordinates } from '@/lib/geo';
import { supabase } from '@/lib/supabase';
import imageCompression from 'browser-image-compression';

interface AddModalProps {
  onClose: () => void;
  userId: string;
  userLocation: Coordinates | null;
  onSuccess: () => void;
}

type Step = 1 | 2 | 3;

export default function AddModal({
  onClose,
  userId,
  userLocation,
  onSuccess,
}: AddModalProps) {
  const [step, setStep] = useState<Step>(1);
  const [photos, setPhotos] = useState<File[]>([]);
  const [photoPreviews, setPhotoPreviews] = useState<string[]>([]);
  const [location, setLocation] = useState<Coordinates>(
    userLocation || DEFAULT_LOCATION
  );
  const [name, setName] = useState('');
  const [category, setCategory] = useState<Category>('snacks');
  const [rating, setRating] = useState(0);
  const [note, setNote] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const miniMapRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<L.Map | null>(null);
  const markerRef = useRef<L.Marker | null>(null);

  // Handle photo selection
  const handlePhotoSelect = useCallback(
    async (newFiles: FileList | File[]) => {
      const remainingSlots = 3 - photos.length;
      if (remainingSlots <= 0) {
        setError('Maximum 3 images allowed');
        return;
      }

      const filesToAdd = Array.from(newFiles).slice(0, remainingSlots);
      const newPhotos = [...photos];
      const newPreviews = [...photoPreviews];

      for (const file of filesToAdd) {
        try {
          const compressed = await imageCompression(file, {
            maxSizeMB: 0.5,
            maxWidthOrHeight: 1200,
            useWebWorker: true,
          });
          newPhotos.push(compressed);
          newPreviews.push(URL.createObjectURL(compressed));
        } catch {
          newPhotos.push(file);
          newPreviews.push(URL.createObjectURL(file));
        }
      }

      setPhotos(newPhotos);
      setPhotoPreviews(newPreviews);
      setError(null);
    },
    [photos, photoPreviews]
  );

  const handleFileChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files) handlePhotoSelect(e.target.files);
    },
    [handlePhotoSelect]
  );


  const removePhoto = (index: number) => {
    setPhotos(photos.filter((_, i) => i !== index));
    setPhotoPreviews(photoPreviews.filter((_, i) => i !== index));
  };

  // Handle "Use My Location"
  const handleUseMyLocation = useCallback(async () => {
    try {
      const coords = await getCurrentPosition();
      setLocation(coords);
      if (mapInstanceRef.current && markerRef.current) {
        mapInstanceRef.current.flyTo([coords.lat, coords.lng], 17);
        markerRef.current.setLatLng([coords.lat, coords.lng]);
      }
    } catch {
      setError('Could not get your location');
    }
  }, []);

  // Initialize mini map for step 2
  useEffect(() => {
    if (step !== 2 || !miniMapRef.current || mapInstanceRef.current) return;

    // Dynamic import for leaflet
    import('leaflet').then((L) => {
      if (!miniMapRef.current) return;

      const map = L.map(miniMapRef.current, {
        center: [location.lat, location.lng],
        zoom: 16,
        zoomControl: true,
        attributionControl: false,
      });

      L.tileLayer(
        'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png',
        { subdomains: 'abcd', maxZoom: 19 }
      ).addTo(map);

      const marker = L.marker([location.lat, location.lng], {
        draggable: true,
      }).addTo(map);

      marker.on('dragend', () => {
        const pos = marker.getLatLng();
        setLocation({ lat: pos.lat, lng: pos.lng });
      });

      map.on('click', (e: L.LeafletMouseEvent) => {
        marker.setLatLng(e.latlng);
        setLocation({ lat: e.latlng.lat, lng: e.latlng.lng });
      });

      mapInstanceRef.current = map;
      markerRef.current = marker;
    });

    return () => {
      if (mapInstanceRef.current) {
        mapInstanceRef.current.remove();
        mapInstanceRef.current = null;
        markerRef.current = null;
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [step]);

  // Submit
  const handleSubmit = useCallback(async () => {
    if (!name.trim()) {
      setError('Please enter a stall name');
      return;
    }
    if (rating === 0) {
      setError('Please select a rating');
      return;
    }

    setSubmitting(true);
    setError(null);

    try {
      const photoUrls: string[] = [];

      // Upload photos
      for (const photo of photos) {
        const ext = photo.name.split('.').pop() || 'jpg';
        const filePath = `posts/${Date.now()}_${Math.random().toString(36).slice(2)}.${ext}`;

        const { error: uploadError } = await supabase.storage
          .from('photos')
          .upload(filePath, photo, { contentType: photo.type });

        if (uploadError) throw uploadError;

        const {
          data: { publicUrl },
        } = supabase.storage.from('photos').getPublicUrl(filePath);
        photoUrls.push(publicUrl);
      }

      const primaryPhotoUrl = photoUrls[0] || null;

      // Create stall
      const { data: stallData, error: stallError } = await supabase
        .from('stalls')
        .insert({
          name: name.trim(),
          category,
          lat: location.lat,
          long: location.lng,
          created_by: userId,
          photo_url: primaryPhotoUrl,
        })
        .select()
        .single();

      if (stallError) throw stallError;

      // Create rating
      await supabase.from('ratings').insert({
        stall_id: stallData.id,
        user_id: userId,
        rating,
        note: note.trim() || null,
      });

      // Create post
      await supabase.from('posts')
        .insert({
          stall_id: stallData.id,
          user_id: userId,
          photo_url: primaryPhotoUrl,
          caption: note.trim() || `Added ${name.trim()}`,
          rating,
          // Support multiple photos in the future if we add a column, 
          // but for now let's just use the first/main photo for the post
        });

      onSuccess();
      onClose();
    } catch (err: unknown) {
      console.error('Failed to add stall:', err);
      if (err instanceof Error) {
        setError(err.message || 'Failed to add stall');
      } else {
        setError('Failed to add stall');
      }
    }

    setSubmitting(false);
  }, [name, category, location, rating, note, photos, userId, onSuccess, onClose]);

  return (
    <div className={styles.overlay} onClick={onClose}>
      <div className={styles.modal} onClick={(e) => e.stopPropagation()}>
        {/* Header */}
        <div className={styles.header}>
          <h2 className={styles.title}>Add a Stall</h2>
          <button className={styles.closeBtn} onClick={onClose}>
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <line x1="18" y1="6" x2="6" y2="18" />
              <line x1="6" y1="6" x2="18" y2="18" />
            </svg>
          </button>
        </div>

        {/* Step indicator */}
        <div className={styles.steps}>
          {[1, 2, 3].map((s) => (
            <div
              key={s}
              className={`${styles.step} ${s === step ? styles.stepActive : ''} ${
                s < step ? styles.stepDone : ''
              }`}
            >
              {s}
            </div>
          ))}
        </div>

        {/* Step 1: Photo */}
        {step === 1 && (
          <div className={styles.body}>
            <h3 className={styles.stepTitle}>Upload Photos (Max 3)</h3>

            <div className={styles.photoGrid}>
              {photoPreviews.map((url, i) => (
                <div key={url} className={styles.previewItem}>
                  <img src={url} alt="Preview" className={styles.preview} />
                  <button className={styles.removePhoto} onClick={() => removePhoto(i)}>×</button>
                </div>
              ))}

              {photos.length < 3 && (
                <div
                  className={styles.dropzone}
                  onClick={() => fileInputRef.current?.click()}
                >
                  <div className={styles.dropzoneContent}>
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                      <rect x="3" y="3" width="18" height="18" rx="2" ry="2" />
                      <circle cx="8.5" cy="8.5" r="1.5" />
                      <polyline points="21 15 16 10 5 21" />
                    </svg>
                    <span>Add Photo</span>
                  </div>
                </div>
              )}
            </div>

            <input
              ref={fileInputRef}
              type="file"
              accept="image/*"
              multiple
              onChange={handleFileChange}
              hidden
            />

            {error && <p className={styles.error}>{error}</p>}

            <div className={styles.footer}>
              <button
                className="btn btn-primary"
                onClick={() => setStep(2)}
                disabled={photos.length === 0}
              >
                Next
              </button>
            </div>
          </div>
        )}

        {/* Step 2: Location */}
        {step === 2 && (
          <div className={styles.body}>
            <div className={styles.stepHeaderRow}>
              <h3 className={styles.stepTitle}>Pick Location</h3>
              <button 
                className={`${styles.locateBtn} glass`}
                onClick={handleUseMyLocation}
              >
                📍 Use My Location
              </button>
            </div>
            <p className={styles.stepDesc}>
              Click the map or drag the marker to set the stall location.
            </p>
            <div ref={miniMapRef} className={styles.miniMap} />
            <div className={styles.coords}>
              <span className="mono">
                {location.lat.toFixed(5)}, {location.lng.toFixed(5)}
              </span>
            </div>
            {error && <p className={styles.error}>{error}</p>}
            <div className={styles.footer}>
              <button className="btn btn-ghost" onClick={() => setStep(1)}>
                Back
              </button>
              <button className="btn btn-primary" onClick={() => setStep(3)}>
                Next
              </button>
            </div>
          </div>
        )}

        {/* Step 3: Details */}
        {step === 3 && (
          <div className={styles.body}>
            <h3 className={styles.stepTitle}>Stall Details</h3>

            <div className={styles.field}>
              <label className={styles.label}>Name *</label>
              <input
                className="input-field"
                placeholder="e.g. Rahim's Fuchka Corner"
                value={name}
                onChange={(e) => setName(e.target.value)}
                autoFocus
              />
            </div>

            <div className={styles.field}>
              <label className={styles.label}>Category</label>
              <div className={styles.categoryGrid}>
                {CATEGORIES.map((cat) => (
                  <button
                    key={cat.value}
                    className={`${styles.catBtn} ${
                      category === cat.value ? styles.catActive : ''
                    }`}
                    onClick={(e) => {
                      e.preventDefault();
                      setCategory(cat.value);
                    }}
                  >
                    <span className={styles.iconWrapper}>
                      <Image src={cat.icon} alt={cat.label} width={20} height={20} className={styles.categoryIcon} unoptimized />
                    </span>
                    <span>{cat.label}</span>
                  </button>
                ))}
              </div>
            </div>

            <div className={styles.field}>
              <label className={styles.label}>Your Rating *</label>
              <RatingStars
                rating={rating}
                interactive
                size="lg"
                onChange={setRating}
              />
            </div>

            <div className={styles.field}>
              <label className={styles.label}>Note (optional)</label>
              <textarea
                className={`input-field ${styles.textarea}`}
                placeholder="What makes this stall special?"
                value={note}
                onChange={(e) => setNote(e.target.value)}
                rows={3}
              />
            </div>

            {error && <p className={styles.error}>{error}</p>}

            <div className={styles.footer}>
              <button className="btn btn-ghost" onClick={() => setStep(2)}>
                Back
              </button>
              <button
                className="btn btn-primary"
                onClick={handleSubmit}
                disabled={submitting}
              >
                {submitting ? 'Adding...' : 'Add Stall'}
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

